  <el-input\r\n                                        ref=\"internal_id\"\r\n                                        v-model=\"form.internal_id\"\r\n                                        dusk=\"internal_id\"\r\n                                    >\r\n                                        <i\r\n                                            slot=\"prefix\"\r\n                                            class=\"el-icon-edit-outline\"\r\n                                        ></i\r\n                                    ></el-input>\r\n                                    <small\r\n                                        class=\"text-danger\"\r\n                                        v-if=\"errors.internal_id\"\r\n                                        v-text=\"errors.internal_id[0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n                            <div class=\"col-md-6\">\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{\r\n                                        'has-danger': errors.description\r\n                                    }\"\r\n                                >\r\n                                    <label class=\"control-label\"\r\n                                        >Nombre<span class=\"text-danger\"\r\n                                            >*</span\r\n                                        ></label\r\n                                    >\r\n                                    <el-input\r\n                                        v-model=\"form.description\"\r\n                                        dusk=\"description\"\r\n                                    >\r\n                                        <i\r\n                                            slot=\"prefix\"\r\n                                            class=\"el-icon-edit-outline\"\r\n                                        ></i>\r\n                                    </el-input>\r\n                                    <small\r\n                                        class=\"text-danger\"\r\n                                        v-if=\"errors.description\"\r\n                                        v-text=\"errors.description[0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n                            <div class=\"col-md-3\">\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{\r\n                                        'has-danger': errors.second_name\r\n                                    }\"\r\n                                >\r\n                                    <label class=\"control-label\"\r\n                                        >Nombre secundario\r\n                                    </label>\r\n                                    <el-input\r\n                                        v-model=\"form.second_name\"\r\n                                        dusk=\"second_name\"\r\n                                    >\r\n                                        <i\r\n                                            slot=\"prefix\"\r\n                                            class=\"el-icon-edit-outline\"\r\n                                        ></i\r\n                                    ></el-input>\r\n                                    <small\r\n                                        class=\"text-danger\"\r\n                                        v-if=\"errors.second_name\"\r\n                                        v-text=\"errors.second_name[0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n                            <div class=\"col-md-3\">\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{\r\n                                        'has-danger': errors.category_id\r\n                                    }\"\r\n                                >\r\n                                    <label class=\"control-label\">\r\n                                        Categoría\r\n                                    </label>\r\n\r\n                                    <a\r\n                                        href=\"#\"\r\n                                        v-if=\"form_category.add == false\"\r\n                                        class=\"control-label font-weight-bold text-info\"\r\n                                        @click=\"form_category.add = true\"\r\n                                    >\r\n                                        [ + Nuevo]</a\r\n                                    >\r\n                                    <a\r\n                                        href=\"#\"\r\n                                        v-if=\"form_category.add == true\"\r\n                                        class=\"control-label font-weight-bold text-info\"\r\n                                        @click=\"saveCategory()\"\r\n                                    >\r\n                                        [ + Guardar]</a\r\n                                    >\r\n                                    <a\r\n                                        href=\"#\"\r\n                                        v-if=\"form_category.add == true\"\r\n                                        class=\"control-label font-weight-bold text-danger\"\r\n                                        @click=\"form_category.add = false\"\r\n                                    >\r\n                                        [ Cancelar]</a\r\n                                    >\r\n                                    <el-input\r\n                                        v-if=\"form_category.add == true\"\r\n                                        v-model=\"form_category.name\"\r\n                                        dusk=\"item_code\"\r\n                                        style=\"margin-bottom:1.5%;\"\r\n                                    >\r\n                                        <i\r\n                                            slot=\"prefix\"\r\n                                            class=\"el-icon-edit-outline\"\r\n                                        ></i\r\n                                    ></el-input>\r\n\r\n                                    <el-select\r\n                                        v-if=\"form_category.add == false\"\r\n                                        v-model=\"form.category_id\"\r\n                                        filterable\r\n                                        clearable\r\n                                    >\r\n                                        <el-option\r\n                                            v-for=\"option in categories\"\r\n                                            :key=\"option.id\"\r\n                                            :value=\"option.id\"\r\n                                            :label=\"option.name\"\r\n                                        ></el-option>\r\n                                    </el-select>\r\n                                    <small\r\n                                        class=\"text-danger\"\r\n                                        v-if=\"errors.category_id\"\r\n                                        v-text=\"errors.category_id[0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n                            <div class=\"col-md-3\">\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{\r\n                      