/div>\r\n\r\n                            <div class=\"col-md-3\">\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{\r\n                                        'has-danger':\r\n                                            errors.sale_affectation_igv_type_id\r\n                                    }\"\r\n                                >\r\n                                    <label class=\"control-label\"\r\n                                        >Tipo de afectación (Venta)</label\r\n                                    >\r\n                                    <el-select\r\n                                        v-model=\"\r\n                                            form.sale_affectation_igv_type_id\r\n                                        \"\r\n                                        @change=\"changeAffectationIgvType\"\r\n                                    >\r\n                                        <el-option\r\n                                            v-for=\"option in affectation_igv_types\"\r\n                                            :key=\"option.id\"\r\n                                            :value=\"option.id\"\r\n                                            :label=\"option.description\"\r\n                                        ></el-option>\r\n                                    </el-select>\r\n                                    <small\r\n                                        class=\"text-danger\"\r\n                                        v-if=\"\r\n                                            errors.sale_affectation_igv_type_id\r\n                                        \"\r\n                                        v-text=\"\r\n                                            errors\r\n                                                .sale_affectation_igv_type_id[0]\r\n                                        \"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n\r\n                            <div\r\n                                class=\"col-md-3\"\r\n                                v-show=\"\r\n                                    recordId == null &&\r\n                                        form.unit_type_id != 'ZZ'\r\n                                \"\r\n                            >\r\n                                <div\r\n                                    class=\"form-group\"\r\n                                    :class=\"{ 'has-danger': errors.stock }\"\r\n                                >\r\n                                    <label\r\n                                        v-if=\"!allEstablishment\"\r\n                                        class=\"control-label\"\r\n                                        >Stock Inicial</label\r\n                                    >\r\n                                    <label v-else class=\"control-label\">\r\n                                        Stock Inicial en cada establecimiento\r\n                                    </label>\r\n                                    <el-input v-model=\"form.stock\">\r\n                                        <i\r\n                                            slot=\"prefix\"\r\n                                            class=\"el-icon-edit-outline\"\r\n                                        ></i\r\n                                    ></el-input>\r\n                                    <small\r\n                                        class=\"text-danger\"\r\n                                        v-if=\"errors.stock\"\r\n                                        v-text=\"errors.stock[0]\"\r\n                                    ></small>\r\n                                </div>\r\n                            </div>\r\n                            <div class=\"col-md-3\">\r\n                        <div class=\"form-group\" :class=